function buildNuclei(width, count) {
  const result = [];
  const margin = 30;
  const attempts = count * 10;
  let placed = 0;
  for (let i = 0; i < attempts && placed < count; i++) {
    const x = margin + Math.random() * (width - margin * 2);
    const y = margin + Math.random() * (CANVAS_HEIGHT - margin * 2);
    const radius = NUCLEUS_R_MIN + Math.random() * (NUCLEUS_R_MAX - NUCLEUS_R_MIN);
    let ok = true;
    for (const n of result) {
      const dx = n.x - x;
      const dy = n.y - y;
      if (Math.sqrt(dx * dx + dy * dy) < radius + NUCLEUS_R_MAX + 8) {
        ok = false;
        break;
      }
    }
    if (ok) {
      result.push({
        id: placed,
        x,
        y,
        radius,
        spent: false,
        burstTime: 0,
        pulseOffset: Math.random() * Math.PI * 2
      });
      placed++;
    }
  }
  return result;
}
function fireNeutronFromEdge(width, speed, nextId) {
  const edge = Math.floor(Math.random() * 4);
  let x;
  let y;
  let vx;
  let vy;
  const spd = speed * (0.8 + Math.random() * 0.4);
  if (edge === 0) {
    x = Math.random() * width;
    y = 0;
  } else if (edge === 1) {
    x = width;
    y = Math.random() * CANVAS_HEIGHT;
  } else if (edge === 2) {
    x = Math.random() * width;
    y = CANVAS_HEIGHT;
  } else {
    x = 0;
    y = Math.random() * CANVAS_HEIGHT;
  }
  const cx = width / 2 + (Math.random() - 0.5) * width * 0.4;
  const cy = CANVAS_HEIGHT / 2 + (Math.random() - 0.5) * CANVAS_HEIGHT * 0.4;
  const len = Math.sqrt((cx - x) ** 2 + (cy - y) ** 2);
  vx = (cx - x) / len * spd;
  vy = (cy - y) / len * spd;
  return {
    id: nextId,
    x,
    y,
    vx,
    vy,
    age: 0,
    maxAge: NEUTRON_MAX_AGE,
    trail: []
  };
}
